head.script:
scwin.statusFlag = "";
scwin.processFlag = "";
scwin.invoiceCheck = "0";
scwin.tabNo = 0;
scwin.mhnoFlag = "0";
scwin.exRateCheck = "1";
scwin.exRate1 = "0";
scwin.exRate2 = "0";
scwin.crc = "";

scwin.v_linkcheck = "";
scwin.v_kcomcd = "";
scwin.v_blno = "";
scwin.v_mhno = "";
scwin.v_bkno = "";

scwin.hd_kcomcd = "DBEX";
scwin.hd_hhio = "I";
scwin.hd_hhitem = "";
scwin.hd_creadyDt = "";
scwin.hd_hhpcgb = "";
scwin.hd_hhdanggb = "";
scwin.hd_commcustomer = "999999";
scwin.ed_hhbltype = "";

scwin.txt_hhlodnm = "";
scwin.txt_hhdiscnm = "";
scwin.txt_hhagentnm = "";
scwin.txt_hhactcustnm = "";
scwin.txt_hhlinernm = "";

scwin.p_seaExgbIm = "";
scwin.p_clntNo = "";
scwin.p_no = "";
scwin.p_row_cnt = "";
scwin.p_data = "";
scwin.p_hblno = "";
scwin.p_docuno = "";
scwin.strCurDate = "";
scwin.userId = "";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.userId = $c.ses.getUserId();
    scwin.p_seaExgbIm = (scwin.params && scwin.params.seaExgbIm) ? scwin.params.seaExgbIm : "";
    scwin.p_clntNo = (scwin.params && scwin.params.clntNo) ? scwin.params.clntNo : "";
    scwin.strCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    scwin.v_linkcheck = (scwin.params && scwin.params.linkcheck) ? scwin.params.linkcheck : "0";
    scwin.v_kcomcd = (scwin.params && scwin.params.kcomcd) ? scwin.params.kcomcd : "";
    scwin.v_blno = (scwin.params && scwin.params.blno) ? scwin.params.blno : "";
    scwin.v_mhno = (scwin.params && scwin.params.mhno) ? scwin.params.mhno : "";
    scwin.v_bkno = (scwin.params && scwin.params.bkno) ? scwin.params.bkno : "";
    scwin.p_no = (scwin.params && scwin.params.no) ? scwin.params.no : "";
    scwin.p_row_cnt = (scwin.params && scwin.params.row_cnt) ? scwin.params.row_cnt : "";
    scwin.p_data = (scwin.params && scwin.params.data) ? scwin.params.data : "";
    scwin.p_hblno = (scwin.params && scwin.params.hblno) ? scwin.params.hblno : "";
    scwin.p_docuno = (scwin.params && scwin.params.docuno) ? scwin.params.docuno : "";

    scwin.f_DefaultValue();
    scwin.f_Check();
    scwin.f_ContainerTypeLoading();
    scwin.f_CurrencyLoading();
    scwin.f_getParametrSetting(scwin.v_linkcheck);
};

scwin.f_getParametrSetting = function(gubun) {
    switch (gubun) {
        case "0":
            break;
        case "5":
            scwin.mhnoFlag = "1";
            if (scwin.v_blno == "null" || scwin.v_blno == "") {
                cnd_ed_hhblno.setValue("");
                cnd_ed_hhblno.setFocus();
                return false;
            }
            scwin.hd_kcomcd = scwin.v_kcomcd;
            cnd_ed_hhblno.setValue(scwin.v_blno);
            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow();
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.v_mhno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.v_mhno);
            break;
        case "9":
            scwin.mhnoFlag = "1";
            cnd_ed_hhblno.setValue(scwin.p_hblno);
            if (ds_hmhno.getRowCount() == 0) {
                ds_hmhno.insertRow();
            }
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "code", scwin.p_docuno);
            ds_hmhno.setCellData(ds_hmhno.getRowPosition(), "name", scwin.p_docuno);
            break;
    }
};

scwin.f_Check = async function() {
};

scwin.f_DefaultValue = async function() {
    scwin.f_Set("INIT");
    cnd_ed_hhblno.setFocus();
};

scwin.f_selectTabMenu = async function(idx) {
    switch (idx) {
        case 0:
            scwin.tabNo = 0;
            ds_retrieve.set("tabIndex", "0");
            break;
        case 1:
            scwin.tabNo = 1;
            ds_retrieve.set("tabIndex", "1");
            break;
        case 2:
            scwin.tabNo = 2;
            ds_retrieve.set("tabIndex", "2");
            break;
    }
};

scwin.f_Set = async function(gubun) {
    switch (gubun) {
        case "INIT":
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Cancel, btn_Save, btn_Delete, btn_Update,
                btn_1, btn_2, btn_3, btn_4, btn_5, btn_6, btn_7, btn_8, btn_9, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1,
                btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2,
                btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3]);
            $c.gus.cfEnableBtnOnly([btn_7]);
            scwin.f_DisablePopUpObj();
            scwin.statusFlag = "I";
            break;
        case "RETRIEVE":
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_1, btn_2, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1,
                btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2,
                btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3, pu_ResultdateChange]);
            $c.gus.cfEnableBtnOnly([btn_Delete, btn_3, btn_4, btn_5, btn_6, btn_7, btn_8, btn_9]);
            gr_selling.setReadOnly("grid", true);
            gr_partner.setReadOnly("grid", true);
            gr_buying.setReadOnly("grid", true);
            if (scwin.statusFlag == "C") {
                $c.gus.cfDisableBtnOnly([btn_Update]);
            } else {
                $c.gus.cfEnableBtnOnly([btn_Update]);
            }
            scwin.statusFlag = "";
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Delete, btn_3, btn_4, btn_5, btn_6, btn_8, btn_9]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel,
                btn_1, btn_2, btn_7, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_DelAll1, btn_CancelRow1,
                btn_AddRow2, btn_DelRow2, btn_DelAll2, btn_CancelRow2,
                btn_AddRow3, btn_DelRow3, btn_DelAll3, btn_CancelRow3, pu_ResultdateChange]);
            gr_selling.setReadOnly("grid", false);
            gr_partner.setReadOnly("grid", false);
            gr_buying.setReadOnly("grid", false);
            scwin.statusFlag = "C";
            break;
        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Delete, btn_3, btn_4, btn_5, btn_6]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel,
                btn_1, btn_7, btn_exChg, btn_cusChg,
                btn_AddRow1, btn_DelRow1, btn_CancelRow1, btn_DelAll1,
                btn_AddRow2, btn_DelRow2, btn_CancelRow2, btn_DelAll2,
                btn_AddRow3, btn_DelRow3, btn_CancelRow3, btn_DelAll3]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            gr_selling.setReadOnly("grid", false);
            gr_partner.setReadOnly("grid", false);
            gr_buying.setReadOnly("grid", false);
            scwin.statusFlag = "U";
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Update]);
            scwin.f_Set("RETRIEVE");
            break;
    }
};

scwin.f_EnablePopUpObj = async function() {
    $c.gus.cfEnableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7, img_PopUp8, img_PopUp9]);
};

scwin.f_DisablePopUpObj = async function() {
    $c.gus.cfDisableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7, img_PopUp8, img_PopUp9]);
};

scwin.f_Retrieve = async function() {
    if (cnd_ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);
        return;
    }
    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("mhno", acb_hhexgb.getValue());
    ds_retrieve.set("hhio", scwin.hd_hhio);
    await $c.sbm.execute(sbm_retrieve);
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    ds_profit.removeAll();
    await $c.sbm.execute(sbm_RetrieveProfit);
};

scwin.f_Retrieve2 = async function() {
    if (ds_houseblList.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["Exchange Rate Information", "상단의 Search"]);
        return;
    }
    if (srch_ed_hhblno.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House No"]);
        return;
    }
    ds_retrieve.set("kcomcd", scwin.hd_kcomcd);
    ds_retrieve.set("mhno", cnd_lc_mhno2.getValue());
    ds_retrieve.set("hhio", scwin.hd_hhio);
    if (ds_retrieve.get("tabIndex") == "") {
        ds_retrieve.set("tabIndex", "0");
    }
    let idx = ds_retrieve.get("tabIndex");
    switch (idx) {
        case "0":
            if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(ds_selling.getRowPosition(), "tabIndex") == "") {
                await $c.win.alert("조회된 Selling데이터가 있습니다.\nSelling데이터가 0건일 경우 조회가능합니다.");
            } else {
                await $c.sbm.execute(sbm_retrieveSelling);
            }
            break;
        case "1":
            if (ds_partner.getRowCount() > 0 && ds_partner.getCellData(ds_partner.getRowPosition(), "tabIndex") == "") {
                await $c.win.alert("조회된 Partner데이터가 있습니다.\nPartner데이터가 0건일 경우 조회가능합니다.");
            } else {
                await $c.sbm.execute(sbm_retrievePartner);
            }
            break;
        case "2":
            if (ds_buying.getRowCount() > 0 && ds_buying.getCellData(ds_buying.getRowPosition(), "tabIndex") == "") {
                await $c.win.alert("조회된 Buying데이터가 있습니다.\nBuying데이터가 0건일 경우 조회가능합니다.");
            } else {
                await $c.sbm.execute(sbm_retrieveBuying);
            }
            break;
    }
    $c.gus.cfEnableObj(srch_ed_hhblno, true);
};

scwin.f_FieldClear = async function() {
    $c.gus.cfInitObjects([cnd_ed_hhblno, cnd_ed_hhmblno]);
    ds_hmhno.removeAll();
};

scwin.f_FieldClear2 = async function() {
    $c.gus.cfInitObjects([srch_ed_hhblno]);
    ds_hmhno2.removeAll();
};

scwin.f_dataSetClear = async function() {
    ds_houseblList.removeAll();
    ds_selling.removeAll();
    ds_partner.removeAll();
    ds_buying.removeAll();
};

scwin.f_Create = async function() {
};

scwin.f_Update = async function() {
    if (cnd_ed_hhblno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
        return;
    } else {
        scwin.f_Set("UPDATE");
        if (ed_hhcur.getValue() == "") ed_hhcur.setValue("USD");
        if (acb_hhexgb.getValue() == "") {
            acb_hhexgb.setValue(scwin.p_seaExgbIm);
        }
        if (ica_hhcurdt.getValue() == "") ica_hhcurdt.setValue(ica_hheta.getValue());
    }
};

scwin.f_Save = async function() {
    if (ds_houseblList.isUpdated() || ds_selling.isUpdated() || ds_partner.isUpdated() || ds_buying.isUpdated()) {
        if (await scwin.f_validate() && scwin.f_JobCloseYn()) {
            let chk = await $c.win.confirm(E_MSG_CM_CRM_001);
            if (chk) {
                if (scwin.statusFlag == "C") {
                    let pos = ds_houseblList.getRowPosition();
                    ds_houseblList.setCellData(pos, "kcomcd", scwin.hd_kcomcd);
                    ds_houseblList.setCellData(pos, "hhblno", cnd_ed_hhblno.getValue());
                    ds_houseblList.setCellData(pos, "mhno", acb_hhexgb.getValue());
                    ds_houseblList.setCellData(pos, "hhio", scwin.hd_hhio);
                    ds_houseblList.setCellData(pos, "inpid", scwin.userId);
                }
                scwin.v_linkcheck = "";
                await $c.sbm.execute(sbm_save);
            }
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["House B/L Freight"]);
    }
};

scwin.f_Cancel = async function() {
    $c.gus.cfEnableObj(cnd_ed_hhblno, true);
    cnd_ed_hhblno.setFocus();
    scwin.f_Set("RETRIEVE");
    ds_houseblList.undoAll();
    scwin.f_cancelRow(1);
    scwin.f_cancelRow(2);
    scwin.f_cancelRow(3);
};

scwin.f_Delete = async function() {
    if (ds_selling.getRowCount() == 0 && ds_partner.getRowCount() == 0 && ds_buying.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_049, ["Freight Information"]);
        return;
    }
    scwin.f_invoiceCheck();
    if (scwin.invoiceCheck == "1") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
        return;
    }
    let chk = await $c.win.confirm(MSG_CM_CRM_004);
    if (chk) {
        for (let i = ds_selling.getRowCount() - 1; i >= 0; i--) {
            ds_selling.removeRow(i);
        }
        for (let i = ds_partner.getRowCount() - 1; i >= 0; i--) {
            ds_partner.removeRow(i);
        }
        for (let i = ds_buying.getRowCount() - 1; i >= 0; i--) {
            ds_buying.removeRow(i);
        }
        await $c.sbm.execute(sbm_delete);
        ds_selling.removeAll();
        ds_partner.removeAll();
        ds_buying.removeAll();
        $c.gus.cfEnableObj(cnd_ed_hhblno, true);
        cnd_ed_hhblno.setFocus();
        scwin.f_Set("INIT");
    }
};

scwin.f_addRow = async function(disGubun) {
    let row;
    switch (disGubun) {
        case 1:
            if (cnd_ed_hhblno.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
            } else {
                if (ds_selling.getRowCount() == 0 || ds_selling.getRowCount() == ds_selling.getRowPosition() + 1) {
                    ds_selling.insertRow();
                    row = ds_selling.getRowPosition();
                } else {
                    ds_selling.insertRow(ds_selling.getRowPosition() + 1);
                    row = ds_selling.getRowPosition();
                }
                ds_selling.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                ds_selling.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
                ds_selling.setCellData(row, "mhno", acb_hhexgb.getValue());
                ds_selling.setCellData(row, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));
                ds_selling.setCellData(row, "drcrCls", "D");
                ds_selling.setCellData(row, "locPtnCls", "1");
                ds_selling.setCellData(row, "mblHblCls", "H");
                ds_selling.setCellData(row, "seaAirCls", "S");
                ds_selling.setCellData(row, "ppccCls", scwin.hd_hhpcgb);
                ds_selling.setCellData(row, "inpid", scwin.userId);
                ds_selling.setCellData(row, "bilgClntNo", ed_hhactcust.getValue());
                ds_selling.setCellData(row, "bilgClntNm", scwin.txt_hhactcustnm);
                ds_selling.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
                ds_selling.setCellData(row, "exRateTyp", acb_hhexgb.getValue());
                scwin.f_sellingUnitLoading();
                ds_selling.setCellData(row, "fareUnit", ds_sellingUnit.getCellData(0, "code"));
                scwin.f_packageRateSellingLoading(row, "");
                gr_selling.setFocusedCell(row, "bilgClntNo");
                if (ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhbltype") == "L") {
                    ds_selling.setCellData(row, "fareUnit", "R/T");
                    scwin.f_packageRateSellingLoading(row, "");
                    gr_selling.setFocusedCell(row, "bilgClntNo");
                }
            }
            break;
        case 2:
            if (cnd_ed_hhblno.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
            } else {
                if (ds_partner.getRowCount() == 0 || ds_partner.getRowCount() == ds_partner.getRowPosition() + 1) {
                    ds_partner.insertRow();
                    row = ds_partner.getRowPosition();
                } else {
                    ds_partner.insertRow(ds_partner.getRowPosition() + 1);
                    row = ds_partner.getRowPosition();
                }
                ds_partner.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                ds_partner.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
                ds_partner.setCellData(row, "mhno", acb_hhexgb.getValue());
                ds_partner.setCellData(row, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));
                ds_partner.setCellData(row, "drCrCls", "C");
                ds_partner.setCellData(row, "locPtnCls", "2");
                ds_partner.setCellData(row, "mblHblCls", "H");
                ds_partner.setCellData(row, "seaAirCls", "S");
                ds_partner.setCellData(row, "ppccCls", scwin.hd_hhpcgb);
                ds_partner.setCellData(row, "inpid", scwin.userId);
                ds_partner.setCellData(row, "bilgClntNo", ed_hhagent.getValue());
                ds_partner.setCellData(row, "bilgClntNm", scwin.txt_hhagentnm);
                ds_partner.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
                ds_partner.setCellData(row, "exRateTyp", acb_hhexgb.getValue());
                scwin.f_partnerUnitLoading();
                ds_partner.setCellData(row, "fareUnit", ds_partnerUnit.getCellData(0, "code"));
                scwin.f_packageRatePartnerLoading(row, "");
                gr_partner.setFocusedCell(row, "bilgClntNo");
            }
            break;
        case 3:
            if (cnd_ed_hhblno.getValue() == "") {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
            } else {
                if (ds_buying.getRowCount() == 0 || ds_buying.getRowCount() == ds_buying.getRowPosition() + 1) {
                    ds_buying.insertRow();
                    row = ds_buying.getRowPosition();
                } else {
                    ds_buying.insertRow(ds_buying.getRowPosition() + 1);
                    row = ds_buying.getRowPosition();
                }
                ds_buying.setCellData(row, "kcomcd", scwin.hd_kcomcd);
                ds_buying.setCellData(row, "blNo", cnd_ed_hhblno.getValue());
                ds_buying.setCellData(row, "mhno", acb_hhexgb.getValue());
                ds_buying.setCellData(row, "odrNo", ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "odrNo"));
                ds_buying.setCellData(row, "drcrCls", "C");
                ds_buying.setCellData(row, "locPtnCls", "1");
                ds_buying.setCellData(row, "mblHblCls", "H");
                ds_buying.setCellData(row, "seaAirCls", "S");
                ds_buying.setCellData(row, "ppccCls", scwin.hd_hhpcgb);
                ds_buying.setCellData(row, "inpid", scwin.userId);
                ds_buying.setCellData(row, "pchsClntNo", ed_hhliner.getValue());
                ds_buying.setCellData(row, "pchsClntNm", scwin.txt_hhlinernm);
                ds_buying.setCellData(row, "rsltsStdDt", scwin.hd_creadyDt);
                ds_buying.setCellData(row, "exRateTyp", acb_hhexgb.getValue());
                ds_buying.setCellData(row, "pchsTyp", "1");
                if (row > 0) {
                    ds_buying.setCellData(row, "crcCd", ds_buying.getCellData(row - 1, "crcCd"));
                }
                scwin.f_buyingUnitLoading();
                ds_buying.setCellData(row, "fareUnit", ds_buyingUnit.getCellData(0, "code"));
                scwin.f_packageRateBuyingLoading(row, "");
                gr_buying.setFocusedCell(row, "pchsClntNo");
                if (ds_houseblList.getCellData(ds_houseblList.getRowPosition(), "hhbltype") == "L") {
                    ds_buying.setCellData(row, "fareUnit", "R/T");
                    scwin.f_packageRateBuyingLoading(row, "");
                    gr_buying.setFocusedCell(row, "pchsClntNo");
                }
            }
            break;
    }
};

scwin.f_deleteRow = async function(disGubun) {
    let tmp, tmpRowPosition;
    switch (disGubun) {
        case 1:
            tmp = ds_selling;
            tmpRowPosition = tmp.getRowPosition();
            for (let i = 0; i < tmp.getRowCount(); i++) {
                if (tmp.getCellData(i, "chk") == "T" || i == tmpRowPosition) {
                    if (tmp.getCellData(i, "certiNo") == "") {
                        tmp.removeRow(i);
                        i--;
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                        return;
                    }
                }
            }
            break;
        case 2:
            tmp = ds_partner;
            tmpRowPosition = tmp.getRowPosition();
            for (let i = 0; i < tmp.getRowCount(); i++) {
                if (tmp.getCellData(i, "chk") == "T" || i == tmpRowPosition) {
                    if (tmp.getCellData(i, "certiNo") == "") {
                        tmp.removeRow(i);
                        i--;
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                        return;
                    }
                }
            }
            break;
        case 3:
            tmp = ds_buying;
            tmpRowPosition = tmp.getRowPosition();
            for (let i = 0; i < tmp.getRowCount(); i++) {
                if (tmp.getCellData(i, "chk") == "T" || i == tmpRowPosition) {
                    if (tmp.getCellData(i, "pchsCertiNo") == "") {
                        if (tmp.getCellData(i, "dcsnClsCd") == "확정") {
                            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["확정", "delete"]);
                            return;
                        } else {
                            tmp.removeRow(i);
                            i--;
                        }
                    } else {
                        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                        return;
                    }
                }
            }
            break;
    }
};

scwin.f_deleteAllRow = async function(disGubun) {
    let ds;
    switch (disGubun) {
        case 1:
            if (ds_selling.getCellData(ds_selling.getRowPosition(), "certiNo") == "") {
                ds = ds_selling;
            } else {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                return;
            }
            break;
        case 2:
            if (ds_partner.getCellData(ds_partner.getRowPosition(), "certiNo") == "") {
                ds = ds_partner;
            } else {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                return;
            }
            break;
        case 3:
            if (ds_buying.getCellData(ds_buying.getRowPosition(), "pchsCertiNo") == "") {
                ds = ds_buying;
            } else {
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_041, ["Invoice No", "delete"]);
                return;
            }
            break;
    }
    if (ds) {
        for (let i = ds.getRowCount() - 1; i >= 0; i--) {
            ds.setRowPosition(i);
            await scwin.f_deleteRow(disGubun);
        }
    }
};

scwin.f_cancelRow = async function(disGubun) {
    switch (disGubun) {
        case 1:
            if (ds_selling.getRowCount() > 0 && ds_selling.getCellData(0, "tabIndex") == "0") {
                ds_selling.removeAll();
            } else {
                ds_selling.undoAll();
            }
            break;
        case 2:
            if (ds_partner.getRowCount() > 0 && ds_partner.getCellData(0, "tabIndex") == "1") {
                ds_partner.removeAll();
            } else {
                ds_partner.undoAll();
            }
            break;
        case 3:
            if (ds_buying.getRowCount() > 0 && ds_buying.getCellData(0, "tabIndex") == "2") {
                ds_buying.removeAll();
            } else {
                ds_buying.undoAll();
            }
            break;
    }
};

scwin.f_validate = async function() {
    let chk = await $c.gus.cfValidate([ica_hhcurdt, ica_hheta, gr_selling, gr_partner, gr_buying]);
    if (!chk) return false;

    if (ed_hhcur.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
        ed_hhcur.setFocus();
        return false;
    }
    if (cnd_ed_hhblno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L"]);
        cnd_ed_hhblno.setFocus();
        return false;
    }
    if (ica_hheta.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["ETA"]);
        ica_hheta.setFocus();
        return false;
    }

    for (let i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "bilgClntNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_selling.setFocusedCell(i, "bilgClntNo");
            return false;
        }
        if (ds_selling.getCellData(i, "bilgClntNm") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_selling.setFocusedCell(i, "bilgClntNm");
            return false;
        }
        if (ds_selling.getCellData(i, "fareEngCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_selling.setFocusedCell(i, "fareEngCd");
            return false;
        }
        if (ds_selling.getCellData(i, "crcCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_selling.setFocusedCell(i, "crcCd");
            return false;
        }
        if (ds_selling.getCellData(i, "fareUnit") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_selling.setFocusedCell(i, "fareUnit");
            return false;
        }
    }

    for (let i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "bilgClntNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_partner.setFocusedCell(i, "bilgClntNo");
            return false;
        }
        if (ds_partner.getCellData(i, "bilgClntNm") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_partner.setFocusedCell(i, "bilgClntNm");
            return false;
        }
        if (ds_partner.getCellData(i, "fareEngCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_partner.setFocusedCell(i, "fareEngCd");
            return false;
        }
        if (ds_partner.getCellData(i, "drCrCls") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["D/C"]);
            gr_partner.setFocusedCell(i, "drCrCls");
            return false;
        }
        if (ds_partner.getCellData(i, "crcCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_partner.setFocusedCell(i, "crcCd");
            return false;
        }
        if (ds_partner.getCellData(i, "fareUnit") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_partner.setFocusedCell(i, "fareUnit");
            return false;
        }
    }

    for (let i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getCellData(i, "pchsTyp") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Type"]);
            gr_buying.setFocusedCell(i, "pchsTyp");
            return false;
        }
        if (ds_buying.getCellData(i, "pchsClntNo") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer"]);
            gr_buying.setFocusedCell(i, "pchsClntNo");
            return false;
        }
        if (ds_buying.getCellData(i, "pchsClntNm") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Customer Name"]);
            gr_buying.setFocusedCell(i, "pchsClntNm");
            return false;
        }
        if (ds_buying.getCellData(i, "fareEngCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["F/Code"]);
            gr_buying.setFocusedCell(i, "fareEngCd");
            return false;
        }
        if (ds_buying.getCellData(i, "crcCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Currency"]);
            gr_buying.setFocusedCell(i, "crcCd");
            return false;
        }
        if (ds_buying.getCellData(i, "fareUnit") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Unit"]);
            gr_buying.setFocusedCell(i, "fareUnit");
            return false;
        }
        if (ds_buying.getCellData(i, "pchsTyp") == "3" && ds_buying.getCellData(i, "sellDeptCd") == "") {
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Inner Department"]);
            gr_buying.setFocusedCell(i, "sellDeptCd");
            return false;
        }
    }

    for (let i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getCellData(i, "vatYn") == "0") {
            if (Number(ds_selling.getCellData(i, "vatAmt")) > 0) {
                await $c.win.alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
                gr_selling.setFocusedCell(i, "vatAmt");
                return false;
            }
        }
        if (ds_selling.getCellData(i, "vatYn") == "1") {
            if (Math.abs(Math.round(Number(ds_selling.getCellData(i, "sellAmt")) * 0.1) - Number(ds_selling.getCellData(i, "vatAmt"))) > 1) {
                await $c.win.alert("VAT 금액은 Amount(W)금액의 10%입니다. \nSelling List " + (i + 1) + "번째 금액을 확인하세요.");
                gr_selling.setFocusedCell(i, "vatAmt");
                return false;
            }
            if (ds_selling.getCellData(i, "sellAmt") == "0") {
                await $c.win.alert("Amount(W) 금액이 0입니다. \nSelling List " + (i + 1) + "번째 데이터를 확인하세요.");
                gr_selling.setFocusedCell(i, "sellAmt");
                return false;
            }
        }
    }

    for (let i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getCellData(i, "sellAmt") == "0") {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nPartner List " + (i + 1) + "번째 데이터를 확인하세요.");
            gr_partner.setFocusedCell(i, "sellAmt");
            return false;
        }
    }

    for (let i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getCellData(i, "vatYn") == "0") {
            if (Number(ds_buying.getCellData(i, "vat")) > 0) {
                await $c.win.alert("영세코드와 부가세 금액은 함께 입력될 수 없습니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
                gr_buying.setFocusedCell(i, "vat");
                return false;
            }
        }
        if (ds_buying.getCellData(i, "pchsAmt") == "0") {
            await $c.win.alert("Amount(W) 금액이 0입니다. \nBuying List " + (i + 1) + "번째 데이터를 확인하세요.");
            gr_buying.setFocusedCell(i, "pchsAmt");
            return false;
        }
    }
    return true;
};

