scwin.f_openPgm = function(name) {
    if (name == "Partner") {
        let param = { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mblno: "", mhno: acb_hhexgb.getValue() };
        $c.win.openMenu("Partner Statement", "/ui/il/acc/acpar/ac_104_01_01b.xml", "ac_104_01_01b.xml", param);
    } else if (name == "Invoice") {
        let param = { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mblno: "", mhno: acb_hhexgb.getValue() };
        $c.win.openMenu("Invoice", "/ui/il/acc/acinv/ac_101_01_01b.xml", "ac_101_01_01b.xml", param);
    } else if (name == "Profit") {
        let param = { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mblno: "", mhno: acb_hhexgb.getValue() };
        $c.win.openMenu("Booking Sheet", "/ui/il/pfm/pfbs/pe_101_01_01b.xml", "pe_101_01_01b.xml", param);
    } else if (name == "HouseBLFind") {
        let param = { hhio: scwin.hd_hhio };
        $c.win.openMenu("House B/L Search", "/ui/il/seaout/sobl/se_105_01_02b.xml", "se_105_01_02b.xml", param);
    } else if (name == "HouseBLHeader") {
        let param = { linkcheck: "2", kcomcd: scwin.hd_kcomcd, blno: cnd_ed_hhblno.getValue(), mhno: acb_hhexgb.getValue() };
        $c.win.openMenu("Export House B/L", "/ui/il/seainb/sibl/se_201_01_01b.xml", "se_201_01_01b.xml", param);
    } else if (name == "MFreight") {
        let param = { linkcheck: "6", kcomcd: scwin.hd_kcomcd, blno: cnd_ed_hhblno.getValue(), mhno: acb_hhexgb.getValue() };
        $c.win.openMenu("Import Master B/L Freight", "/ui/il/seainb/sibl/se_202_01_02b.xml", "se_202_01_02b.xml", param);
    } else if (name == "paymentINV") {
        let param = { kcomcd: scwin.hd_kcomcd, seaair: "S", iogb: scwin.hd_hhio, blno: cnd_ed_hhblno.getValue(), mhno: acb_hhexgb.getValue() };
        $c.win.openMenu("Payment Invoice", "/ui/il/acc/acpay/ac_106_01_01b.xml", "ac_106_01_01b.xml", param);
    }
};

