        if (unit == ed_hhcnt1type.getValue()) ds_partner.setCellData(pos, "chgWt", ed_hhcnt1.getValue());
        else if (unit == ed_hhcnt2type.getValue()) ds_partner.setCellData(pos, "chgWt", ed_hhcnt2.getValue());
        else if (unit == ed_hhcnt3type.getValue()) ds_partner.setCellData(pos, "chgWt", ed_hhcnt3.getValue());
        else if (unit == ed_hhcnt4type.getValue()) ds_partner.setCellData(pos, "chgWt", ed_hhcnt4.getValue());
    }
};

scwin.f_packageRateBuyingLoading = function(row, colid) {
    let pos = ds_buying.getRowPosition();
    let v_wgt = Number(ed_hhgwgt.getValue()) / 1000;
    let v_msr = Number(ed_hhmsr.getValue());
    let v_wgtR = Math.ceil(v_wgt);
    let v_msrR = Math.ceil(v_msr);
    let wgt = 0, msr = 0;
    if (ds_buying.getCellData(pos, "fareEngCd") == "WFG") { wgt = v_wgtR; msr = v_msrR; } else { wgt = v_wgt; msr = v_msr; }
    let unit = ds_buying.getCellData(pos, "fareUnit");
    if (unit == "WGT" || unit == "M/T") {
        if (ds_buying.getCellData(pos, "fareEngCd") == "WFG") { ds_buying.setCellData(pos, "chgWt", Math.ceil(Number(ed_hhgwgt.getValue()))); }
        else { ds_buying.setCellData(pos, "chgWt", ed_hhgwgt.getValue()); }
    } else if (unit == "R/T") {
        ds_buying.setCellData(pos, "chgWt", v_wgt > v_msr ? wgt : msr);
    } else if (unit == "CBM") {
        ds_buying.setCellData(pos, "chgWt", msr);
    } else if (unit == "CASE") {
        ds_buying.setCellData(pos, "chgWt", "1");
    } else {
        if (unit == ed_hhcnt1type.getValue()) ds_buying.setCellData(pos, "chgWt", ed_hhcnt1.getValue());
        else if (unit == ed_hhcnt2type.getValue()) ds_buying.setCellData(pos, "chgWt", ed_hhcnt2.getValue());
        else if (unit == ed_hhcnt3type.getValue()) ds_buying.setCellData(pos, "chgWt", ed_hhcnt3.getValue());
        else if (unit == ed_hhcnt4type.getValue()) ds_buying.setCellData(pos, "chgWt", ed_hhcnt4.getValue());
    }
};

