scwin.f_RunExcel = async function(dataId, gridId) {
    let ds = (typeof dataId === "string") ? eval(dataId) : dataId;
    let countA = ds.getRowCount();
    if (countA == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }
    let sheetName = "", fileName = "";
    if (gridId == "gr_selling") { sheetName = "Selling List"; fileName = "Selling List.xlsx"; }
    else if (gridId == "gr_partner") { sheetName = "Partner List"; fileName = "Partner List.xlsx"; }
    else if (gridId == "gr_buying") { sheetName = "Buying List"; fileName = "Buying List.xlsx"; }
    let gridName = eval(gridId);
    $c.data.downloadGridViewExcel(gridName, { fileName: fileName, sheetName: sheetName });
};

scwin.f_JobCloseYn = async function() {
    let preWrkNo = "FI01";
    let minRsltsDt = scwin.strCurDate.substr(0, 6);
    for (let i = 0; i < ds_selling.getRowCount(); i++) {
        if (ds_selling.getRowStatus(i) == "C") {
            if (ds_selling.getCellData(i, "rsltsStdDt").substr(0, 6) < minRsltsDt) {
                minRsltsDt = ds_selling.getCellData(i, "rsltsStdDt").substr(0, 6);
            }
        }
    }
    let isCloseDepr = $c.gus.cfJobCloseYN("CUR", minRsltsDt, "00", preWrkNo, "0", "", "", "000");
    if (isCloseDepr == "2" || isCloseDepr == "DNF") {
        await $c.gus.cfAlertMsg("회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nSelling List Result Date를 확인하세요.");
        return false;
    }

    minRsltsDt = scwin.strCurDate.substr(0, 6);
    for (let i = 0; i < ds_partner.getRowCount(); i++) {
        if (ds_partner.getRowStatus(i) == "C") {
            if (ds_partner.getCellData(i, "rsltsStdDt").substr(0, 6) < minRsltsDt) {
                minRsltsDt = ds_partner.getCellData(i, "rsltsStdDt").substr(0, 6);
            }
        }
    }
    isCloseDepr = $c.gus.cfJobCloseYN("CUR", minRsltsDt, "00", preWrkNo, "0", "", "", "000");
    if (isCloseDepr == "2" || isCloseDepr == "DNF") {
        await $c.gus.cfAlertMsg("회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nPartner List Result Date를 확인하세요.");
        return false;
    }

    minRsltsDt = scwin.strCurDate.substr(0, 6);
    for (let i = 0; i < ds_buying.getRowCount(); i++) {
        if (ds_buying.getRowStatus(i) == "C") {
            if (ds_buying.getCellData(i, "rsltsStdDt").substr(0, 6) < minRsltsDt) {
                minRsltsDt = ds_buying.getCellData(i, "rsltsStdDt").substr(0, 6);
            }
        }
    }
    isCloseDepr = $c.gus.cfJobCloseYN("CUR", minRsltsDt, "00", preWrkNo, "0", "", "", "000");
    if (isCloseDepr == "2" || isCloseDepr == "DNF") {
        await $c.gus.cfAlertMsg("회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nBuying List Result Date를 확인하세요.");
        return false;
    }
    return true;
};

