scwin.f_pkgChange = function(clsCd) {
    let chngValue = 0;
    if (clsCd == "Weight") chngValue = Number(ed_hhgwgt.getValue()) / 1000;
    if (clsCd == "Measure") chngValue = Number(ed_hhmsr.getValue());
    if (scwin.tabNo == 0) {
        for (let i = 0; i < ds_selling.getRowCount(); i++) {
            if (Number(ds_selling.getCellData(i, "chgWt")) != 1) {
                ds_selling.setCellData(i, "chgWt", chngValue);
                if (ds_selling.getCellData(i, "crcCd") == "USD") {
                    ds_selling.setCellData(i, "sellAmtFcrc", Number(ds_selling.getCellData(i, "chgWt")) * Number(ds_selling.getCellData(i, "sellUpr")));
                    ds_selling.setCellData(i, "sellAmt", Number(ds_selling.getCellData(i, "sellAmtFcrc")) * Number(ds_selling.getCellData(i, "exRate")));
                }
                if (ds_selling.getCellData(i, "crcCd") == "KRW") {
                    ds_selling.setCellData(i, "sellAmt", Number(ds_selling.getCellData(i, "chgWt")) * Number(ds_selling.getCellData(i, "sellUpr")));
                }
            }
        }
    }
    if (scwin.tabNo == 1) {
        for (let i = 0; i < ds_partner.getRowCount(); i++) {
            if (Number(ds_partner.getCellData(i, "chgWt")) != 1) {
                ds_partner.setCellData(i, "chgWt", chngValue);
                if (ds_partner.getCellData(i, "crcCd") == "USD") {
                    ds_partner.setCellData(i, "sellAmtFcrc", Number(ds_partner.getCellData(i, "chgWt")) * Number(ds_partner.getCellData(i, "sellUpr")));
                    ds_partner.setCellData(i, "sellAmt", Number(ds_partner.getCellData(i, "sellAmtFcrc")) * Number(ds_partner.getCellData(i, "exRate")));
                }
                if (ds_partner.getCellData(i, "crcCd") == "KRW") {
                    ds_partner.setCellData(i, "sellAmt", Number(ds_partner.getCellData(i, "chgWt")) * Number(ds_partner.getCellData(i, "sellUpr")));
                }
            }
        }
    }
    if (scwin.tabNo == 2) {
        for (let i = 0; i < ds_buying.getRowCount(); i++) {
            if (Number(ds_buying.getCellData(i, "chgWt")) != 1) {
                ds_buying.setCellData(i, "chgWt", chngValue);
                if (ds_buying.getCellData(i, "crcCd") == "USD") {
                    ds_buying.setCellData(i, "pchsAmtFcrc", Number(ds_buying.getCellData(i, "chgWt")) * Number(ds_buying.getCellData(i, "pchsUpr")));
                    ds_buying.setCellData(i, "pchsAmt", Number(ds_buying.getCellData(i, "pchsAmtFcrc")) * Number(ds_buying.getCellData(i, "exRate")));
                }
                if (ds_buying.getCellData(i, "crcCd") == "KRW") {
                    ds_buying.setCellData(i, "pchsAmt", Number(ds_buying.getCellData(i, "chgWt")) * Number(ds_buying.getCellData(i, "pchsUpr")));
                }
            }
        }
    }
};

