scwin.sbm_retrieve_submitdone = async function(e) {
    if (ds_houseblList.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        scwin.f_Set("INIT");
        scwin.f_Check();
    } else {
        scwin.f_invoiceCheck();
        scwin.f_Set("RETRIEVE");
        scwin.f_SellingSum();
        scwin.f_PartnerSum();
        scwin.f_BuyingSum();
    }
    if (scwin.v_linkcheck == "9") {
        scwin.f_Set("UPDATE");
        let no = scwin.p_no;
        let row_cnt = scwin.p_row_cnt;
        let data = scwin.p_data;
        if (data && data != "") {
            let rtnValues = data.split('$');
            for (let t = 0; t < rtnValues.length; t++) {
                rtnValues[t] = rtnValues[t].split('_');
            }
            let k = ds_buying.getRowCount();
            for (let i = 0; i < rtnValues.length; i++) {
                scwin.f_addRow(3);
                let pos = ds_buying.getRowPosition();
                if (pos > 0) {
                    ds_buying.setCellData(pos, "pchsSeq", Number(ds_buying.getCellData(pos - 1, "pchsSeq")) + 1);
                }
                ds_line_condition.set("hhliner", ed_hhliner.getValue());
                ds_line_condition.set("fromCd", rtnValues[i][0]);
                await $c.sbm.execute(sbm_retrieve_frtMapping);
                ds_buying.setCellData(pos, "fareEngCd", ds_frtMapping.getCellData(0, "toCd"));
                ds_buying.setCellData(pos, "fareEngNm", ds_frtMapping.getCellData(0, "description"));
                ds_buying.setCellData(pos, "selpchItemCd", ds_frtMapping.getCellData(0, "dtlCd1"));
                ds_buying.setCellData(pos, "fareGrpCd", ds_frtMapping.getCellData(0, "dtlCd2"));
                ds_buying.setCellData(pos, "vatYn", ds_frtMapping.getCellData(0, "dtlCd3"));
                ds_buying.setCellData(pos, "crcCd", rtnValues[i][1]);
                ds_buying.setCellData(pos, "pchsAmtFcrc", rtnValues[i][2]);
                ds_buying.setCellData(pos, "exRate", rtnValues[i][3]);
                ds_buying.setCellData(pos, "pchsAmt", rtnValues[i][4]);
                ds_buying.setCellData(pos, "chgWt", rtnValues[i][5]);
                ds_buying.setCellData(pos, "pchsUpr", rtnValues[i][6]);
                if (ds_buying.getCellData(pos, "crcCd") == "USD") {
                    ds_buying.setCellData(pos, "usdAmt", rtnValues[i][2]);
                }
            }
        }
    }
};

